# lib/my_app_web/xml/safe_parser.ex
defmodule MyAppWeb.XML.SafeParser do
  @moduledoc """
  Safely parses XML with external entities DISABLED to prevent XXE attacks.
  """

  import SweetXml

  @doc """
  Parses XML string safely by stripping DTD declarations and external entities
  before parsing with SweetXml.
  """
  def safe_parse(xml_string) when is_binary(xml_string) do
    sanitized_xml = sanitize_xml(xml_string)

    try do
      # Use xmerl with safe options - DTD processing disabled
      parsed =
        sanitized_xml
        |> String.to_charlist()
        |> :xmerl_scan.string(
          quiet: true,
          acc_fun: &accumulate/3,
          fetch_fun: &deny_fetch/2,
          rules: :xmerl_scanner
        )

      {:ok, parsed}
    rescue
      e -> {:error, "XML parsing failed: #{inspect(e)}"}
    catch
      :exit, reason -> {:error, "XML parsing failed: #{inspect(reason)}"}
    end
  end

  @doc """
  Parses XML and extracts values using xpath safely.
  """
  def safe_xpath(xml_string, xpath_expr) when is_binary(xml_string) do
    sanitized_xml = sanitize_xml(xml_string)

    try do
      result = sanitized_xml |> xpath(xpath_expr)
      {:ok, result}
    rescue
      e -> {:error, "XPath evaluation failed: #{inspect(e)}"}
    catch
      :exit, reason -> {:error, "XPath evaluation failed: #{inspect(reason)}"}
    end
  end

  @doc """
  Parses XML and extracts multiple values using xmap safely.
  """
  def safe_xmap(xml_string, specs) when is_binary(xml_string) and is_list(specs) do
    sanitized_xml = sanitize_xml(xml_string)

    try do
      result = sanitized_xml |> xmap(specs)
      {:ok, result}
    rescue
      e -> {:error, "XMap evaluation failed: #{inspect(e)}"}
    catch
      :exit, reason -> {:error, "XMap evaluation failed: #{inspect(reason)}"}
    end
  end

  # Strip DOCTYPE declarations and entity definitions to prevent XXE
  defp sanitize_xml(xml_string) do
    xml_string
    |> String.replace(~r/<!DOCTYPE[^>]*(\[.*?\])?>/si, "")
    |> String.replace(~r/<!ENTITY[^>]*>/si, "")
  end

  # Deny all external fetches
  defp deny_fetch(_uri, state) do
    {:ok, {:string, ''}, state}
  end

  defp accumulate(parsed_entity, acc, global_state) do
    {[parsed_entity | acc], global_state}
  end
end

# lib/my_app_web/controllers/soap_controller.ex
defmodule MyAppWeb.SOAPController do
  use MyAppWeb, :controller

  import SweetXml
  alias MyAppWeb.XML.SafeParser

  @doc """
  Handles incoming SOAP requests.
  """
  def handle(conn, %{"_xml_body" => xml_body}) do
    with {:ok, action} <- SafeParser.safe_xpath(xml_body, ~x"//soap:Body/*[1]"l |> transform_by(&local_name/1)),
         {:ok, result} <- process_soap_request(xml_body) do
      conn
      |> put_resp_content_type("text/xml")
      |> send_resp(200, build_soap_response(result))
    else
      {:error, reason} ->
        conn
        |> put_resp_content_type("text/xml")
        |> send_resp(500, build_soap_fault("Server", reason))
    end
  end

  def handle(conn, _params) do
    conn
    |> put_resp_content_type("text/xml")
    |> send_resp(400, build_soap_fault("Client", "No XML body provided"))
  end

  defp process_soap_request(xml_body) do
    # Example: parse a SOAP request for a GetUser operation
    with {:ok, result} <-
           SafeParser.safe_xmap(xml_body, [
             action: ~x"//soap:Body/*[1]"s |> transform_by(&extract_local_name/1),
             namespace: ~x"//soap:Envelope/@xmlns:soap"s
           ]) do
      dispatch_action(xml_body, result)
    end
  end

  defp dispatch_action(xml_body, %{action: action} = _meta) do
    case action do
      "GetUser" ->
        with {:ok, user_id} <- SafeParser.safe_xpath(xml_body, ~x"//GetUser/UserId/text()"s) do
          {:ok, %{user_id: user_id, name: "Example User", email: "user@example.com"}}
        end

      "ListUsers" ->
        {:ok, %{users: [%{id: 1, name: "User 1"}, %{id: 2, name: "User 2"}]}}

      _ ->
        {:error, "Unknown SOAP action: #{action}"}
    end
  end

  defp dispatch_action(_xml_body, _meta) do
    {:error, "Could not determine SOAP action"}
  end

  defp extract_local_name(node) when is_tuple(node) do
    node
    |> SweetXml.xpath(~x"local-name(.)"s)
  end

  defp extract_local_name(value), do: value

  defp local_name(node) when is_tuple(node) do
    SweetXml.xpath(node, ~x"local-name(.)"s)
  end

  defp local_name(value), do: to_string(value)

  defp build_soap_response(result) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <Response>
          #{map_to_xml(result)}
        </Response>
      </soap:Body>
    </soap:Envelope>
    """
  end

  defp build_soap_fault(code, reason) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <soap:Fault>
          <faultcode>soap:#{xml_escape(code)}</faultcode>
          <faultstring>#{xml_escape(to_string(reason))}</faultstring>
        </soap:Fault>
      </soap:Body>
    </soap:Envelope>
    """
  end

  defp map_to_xml(map) when is_map(map) do
    Enum.map_join(map, "\n", fn {key, value} ->
      tag = to_string(key)
      "<#{tag}>#{map_to_xml(value)}</#{tag}>"
    end)
  end

  defp map_to_xml(list) when is_list(list) do
    Enum.map_join(list, "\n", fn item ->
      "<item>#{map_to_xml(item)}</item>"
    end)
  end

  defp map_to_xml(value), do: xml_escape(to_string(value))

  defp xml_escape(string) do
    string
    |> String.replace("&", "&amp;")
    |> String.replace("<", "&lt;")
    |> String.replace(">", "&gt;")
    |> String.replace("\"", "&quot;")
    |> String.replace("'", "&apos;")
  end
end

# lib/my_app_web/router.ex
defmodule MyAppWeb.Router do
  use MyAppWeb, :router

  pipeline :soap do
    plug Plug.Parsers,
      parsers: [MyAppWeb.Plugs.XMLParser],
      pass: ["text/xml", "application/xml"]
  end

  scope "/api/soap", MyAppWeb do
    pipe_through :soap

    post "/", SOAPController, :handle
  end
end

